import{_ as e,o as a,c as l,a3 as o}from"./chunks/framework.BTFg6ESq.js";const c=JSON.parse('{"title":"关于与许可","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/settings/about.md","filePath":"user-guide/settings/about.md","lastUpdated":1781934556000}'),r={name:"user-guide/settings/about.md"};function i(s,t,n,d,h,u){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="关于与许可" tabindex="-1">关于与许可 <a class="header-anchor" href="#关于与许可" aria-label="Permalink to &quot;关于与许可&quot;">​</a></h1><blockquote><p>&quot;关于&quot;页面展示 AIO Hub 的应用信息、版本更新和项目生态。这里是了解应用状态和支持项目的地方。</p></blockquote><hr><h2 id="入口" tabindex="-1">入口 <a class="header-anchor" href="#入口" aria-label="Permalink to &quot;入口&quot;">​</a></h2><ol><li>点击标题栏右侧的 ⚙️ 图标进入设置。</li><li>在设置左侧导航栏中点击最下方的「关于」选项卡。</li></ol><hr><h2 id="应用信息" tabindex="-1">应用信息 <a class="header-anchor" href="#应用信息" aria-label="Permalink to &quot;应用信息&quot;">​</a></h2><p>页面上方展示应用的品牌头部区：</p><table tabindex="0"><thead><tr><th style="text-align:left;">信息</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>应用名称</strong></td><td style="text-align:left;">通过 Tauri API 获取，通常为 &quot;AIO Hub&quot;</td></tr><tr><td style="text-align:left;"><strong>应用版本</strong></td><td style="text-align:left;">当前安装的版本号（如 <code>1.0.0</code>），遵循语义化版本规范</td></tr><tr><td style="text-align:left;"><strong>应用图标</strong></td><td style="text-align:left;">项目彩色图标</td></tr><tr><td style="text-align:left;"><strong>应用简介</strong></td><td style="text-align:left;">&quot;提供多种实用的开发和日常工具，以及高可控性的 LLM 交互&quot;</td></tr></tbody></table><hr><h2 id="检查更新" tabindex="-1">检查更新 <a class="header-anchor" href="#检查更新" aria-label="Permalink to &quot;检查更新&quot;">​</a></h2><h3 id="手动检查" tabindex="-1">手动检查 <a class="header-anchor" href="#手动检查" aria-label="Permalink to &quot;手动检查&quot;">​</a></h3><p>点击版本号旁边的「检查更新」按钮，系统会：</p><ol><li>向 GitHub Releases API 发起请求，获取最新版本信息</li><li>对比当前版本和最新版本的语义化版本号</li><li>如果存在新版本 → 弹出更新弹窗</li><li>如果已是最新版 → 提示&quot;当前已是最新版本&quot;</li></ol><h3 id="强制检测模式" tabindex="-1">强制检测模式 <a class="header-anchor" href="#强制检测模式" aria-label="Permalink to &quot;强制检测模式&quot;">​</a></h3><p>按住 <strong>Alt 键</strong> 的同时点击「检查更新」按钮，会<strong>强制显示更新弹窗</strong>（即使没有新版本）。这在以下场景中很有用：</p><ul><li>想要查看最新的 Release Notes</li><li>确认更新检测功能正常工作</li></ul><h3 id="更新弹窗" tabindex="-1">更新弹窗 <a class="header-anchor" href="#更新弹窗" aria-label="Permalink to &quot;更新弹窗&quot;">​</a></h3><p>弹窗包含：</p><table tabindex="0"><thead><tr><th style="text-align:left;">内容</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>标题</strong></td><td style="text-align:left;">&quot;发现新版本 vX.Y.Z&quot;</td></tr><tr><td style="text-align:left;"><strong>更新日志</strong></td><td style="text-align:left;">使用 <code>RichTextRenderer</code> 渲染 GitHub 的 Release Notes（支持 Markdown）</td></tr><tr><td style="text-align:left;"><strong>按钮</strong></td><td style="text-align:left;">「暂不更新」/「前往下载」→ 跳转到 GitHub Releases 页面</td></tr></tbody></table><blockquote><p>更新弹窗使用项目的 <strong>BaseDialog</strong> 组件，尺寸为 70vw × 80vh，确保更新日志有足够的阅读空间。</p></blockquote><h3 id="更新方式" tabindex="-1">更新方式 <a class="header-anchor" href="#更新方式" aria-label="Permalink to &quot;更新方式&quot;">​</a></h3><p>AIO Hub 目前通过<strong>下载最新安装包覆盖安装</strong>的方式进行更新：</p><ol><li>在更新弹窗中点击「前往下载」</li><li>跳转到 GitHub Releases 页面下载最新版本</li><li>安装新版本，配置和数据不会丢失</li></ol><hr><h2 id="项目信息" tabindex="-1">项目信息 <a class="header-anchor" href="#项目信息" aria-label="Permalink to &quot;项目信息&quot;">​</a></h2><p>页面中段展示核心项目信息：</p><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开发者</strong></td><td style="text-align:left;">miaotouy</td></tr><tr><td style="text-align:left;"><strong>仓库</strong></td><td style="text-align:left;">miaotouy/aio-hub</td></tr><tr><td style="text-align:left;"><strong>许可证</strong></td><td style="text-align:left;">Apache License 2.0</td></tr></tbody></table><p>每个信息项都带有图标标识，简洁明了。</p><hr><h2 id="支持项目" tabindex="-1">支持项目 <a class="header-anchor" href="#支持项目" aria-label="Permalink to &quot;支持项目&quot;">​</a></h2><p>AIO Hub 是一个<strong>完全免费的开源项目</strong>，作者几乎全职投入开发。如果你喜欢这个项目，可以通过以下方式支持：</p><h3 id="支持带来的好处" tabindex="-1">支持带来的好处 <a class="header-anchor" href="#支持带来的好处" aria-label="Permalink to &quot;支持带来的好处&quot;">​</a></h3><ul><li>🚀 持续添加新功能和工具</li><li>🐛 及时修复问题和优化性能</li><li>📚 完善文档和使用教程</li><li>💡 探索更多创新想法</li></ul><h3 id="支持方式" tabindex="-1">支持方式 <a class="header-anchor" href="#支持方式" aria-label="Permalink to &quot;支持方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>⭐ 给项目点个 Star</strong></td><td style="text-align:left;">在 GitHub 上点亮 Star，这是对作者最大的鼓励</td></tr><tr><td style="text-align:left;"><strong>🎁 爱发电赞助</strong></td><td style="text-align:left;">支持作者继续开发维护，探索更多创新功能（高亮卡片）</td></tr></tbody></table><blockquote><p>爱发电赞助卡片有特殊的高亮样式，以渐变色背景和粉红色调标识。</p></blockquote><h3 id="操作方式" tabindex="-1">操作方式 <a class="header-anchor" href="#操作方式" aria-label="Permalink to &quot;操作方式&quot;">​</a></h3><p>点击对应的支持卡片，会自动在浏览器中打开对应的链接：</p><ul><li>GitHub Star → <code>https://github.com/miaotouy/aio-hub</code></li><li>爱发电赞助 → <code>https://afdian.com/a/miaotouy</code></li></ul><hr><h2 id="版权信息" tabindex="-1">版权信息 <a class="header-anchor" href="#版权信息" aria-label="Permalink to &quot;版权信息&quot;">​</a></h2><p>页面底部展示版权信息：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>© 2025 miaotouy. All rights reserved.</span></span></code></pre></div><p>桌面端源代码基于 <strong>Apache License 2.0</strong> 发布，详细信息见项目根目录的 <code>LICENSE</code> 文件。</p><hr><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-如何获取应用的最新版本" tabindex="-1">Q：如何获取应用的最新版本？ <a class="header-anchor" href="#q-如何获取应用的最新版本" aria-label="Permalink to &quot;Q：如何获取应用的最新版本？&quot;">​</a></h3><p>关注 GitHub Releases 页面即可。也可以在「关于」页面中点击「检查更新」按钮手动检查。</p><h3 id="q-更新会丢失我的配置吗" tabindex="-1">Q：更新会丢失我的配置吗？ <a class="header-anchor" href="#q-更新会丢失我的配置吗" aria-label="Permalink to &quot;Q：更新会丢失我的配置吗？&quot;">​</a></h3><p><strong>不会。</strong> 覆盖安装新版本后，所有配置和数据会保留。但为了保险起见，建议在重大更新前使用「通用设置 → 导出配置」功能备份配置。</p><h3 id="q-如何查看许可证详情" tabindex="-1">Q：如何查看许可证详情？ <a class="header-anchor" href="#q-如何查看许可证详情" aria-label="Permalink to &quot;Q：如何查看许可证详情？&quot;">​</a></h3><p>桌面端使用 Apache License 2.0，可以在项目根目录的 <code>LICENSE</code> 文件中查看完整内容。</p><h3 id="q-我想参与项目开发或提建议" tabindex="-1">Q：我想参与项目开发或提建议？ <a class="header-anchor" href="#q-我想参与项目开发或提建议" aria-label="Permalink to &quot;Q：我想参与项目开发或提建议？&quot;">​</a></h3><p>欢迎你在 GitHub 上提交 Issue 或 Pull Request！仓库地址在「关于」页面中有展示。</p><hr><blockquote><p>🔚 你已经读完了设置指南的全部内容。回到 <a href="./">设置概览</a> 查看完整的设置导航。</p></blockquote>',57)])])}const g=e(r,[["render",i]]);export{c as __pageData,g as default};
